// MARK: - Secure API Client
class SecureAPIClient {
    private let session: URLSession
    private let apiKey: String
    private let baseURL: String
    
    init(apiKey: String, baseURL: String) {
        self.apiKey = apiKey
        self.baseURL = baseURL
        let config = URLSessionConfiguration.default
        config.timeoutInterval = 30
        self.session = URLSession(configuration: config)
    }
    
    func fetchStockData(symbol: String, completion: @escaping (Result<StockData, Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/stock/\(symbol)") else {
            completion(.failure(NetworkError.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.setValue("Bearer \(apiKey)", forHTTPHeaderField: "Authorization")
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NetworkError.noData))
                return
            }
            
            do {
                let stockData = try JSONDecoder().decode(StockData.self, from: data)
                completion(.success(stockData))
            } catch {
                completion(.failure(error))
            }
        }
        
        task.resume()
    }
    
    func executeTrade(trade: TradeRequest, completion: @escaping (Result<TradeResponse, Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/trade") else {
            completion(.failure(NetworkError.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("Bearer \(apiKey)", forHTTPHeaderField: "Authorization")
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        do {
            let jsonData = try JSONEncoder().encode(trade)
            request.httpBody = jsonData
        } catch {
            completion(.failure(error))
            return
        }
        
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NetworkError.noData))
                return
            }
            
            do {
                let tradeResponse = try JSONDecoder().decode(TradeResponse.self, from: data)
                completion(.success(tradeResponse))
            } catch {
                completion(.failure(error))
            }
        }
        
        task.resume()
    }
}

// MARK: - Data Models
struct StockData: Codable {
    let symbol: String
    let price: Double
    let change: Double
    let changePercent: Double
    let volume: Int
}

struct TradeRequest: Codable {
    let symbol: String
    let quantity: Int
    let type: TradeType
    let price: Double
}

struct TradeResponse: Codable {
    let orderId: String
    let status: TradeStatus
    let executedPrice: Double
    let executedQuantity: Int
    let timestamp: Date
}

enum TradeType: String, Codable {
    case buy
    case sell
}

enum TradeStatus: String, Codable {
    case pending
    case completed
    case failed
}

enum NetworkError: Error {
    case invalidURL
    case noData
    case invalidResponse
}

// MARK: - Portfolio Manager
class PortfolioManager {
    private var portfolio: [String: Int] = [:]
    private let userDefaults = UserDefaults.standard
    
    init() {
        loadPortfolio()
    }
    
    func addStock(symbol: String, quantity: Int) {
        portfolio[symbol] = (portfolio[symbol] ?? 0) + quantity
        savePortfolio()
    }
    
    func removeStock(symbol: String, quantity: Int) {
        if let currentQuantity = portfolio[symbol] {
            let newQuantity = max(0, currentQuantity - quantity)
            portfolio[symbol] = newQuantity
            if newQuantity == 0 {
                portfolio.removeValue(forKey: symbol)
            }
            savePortfolio()
        }
    }
    
    func getStockQuantity(symbol: String) -> Int {
        return portfolio[symbol] ?? 0
    }
    
    func getAllStocks() -> [String: Int] {
        return portfolio
    }
    
    private func savePortfolio() {
        if let data = try? JSONEncoder().encode(portfolio) {
            userDefaults.set(data, forKey: "portfolio")
        }
    }
    
    private func loadPortfolio() {
        if let data = userDefaults.data(forKey: "portfolio"),
           let loadedPortfolio = try? JSONDecoder().decode([String: Int].self, from: data) {
            portfolio = loadedPortfolio
        }
    }
}

// MARK: - Device Integrity Checker
class DeviceIntegrityChecker {
    static let shared = DeviceIntegrityChecker()
    
    private init() {}
    
    func isDeviceJailbroken() -> Bool {
        // Check for common jailbreak indicators
        if FileManager.default.fileExists(atPath: "/Applications/Cydia.app") {
            return true
        }
        
        if FileManager.default.fileExists(atPath: "/Library/MobileSubstrate/MobileSubstrate.dylib") {
            return true
        }
        
        if FileManager.default.fileExists(atPath: "/bin/bash") {
            // Check if bash is accessible (common on jailbroken devices)
            let task = Process()
            task.executableURL = URL(fileURLWithPath: "/bin/bash")
            task.arguments = ["-c", "echo test"]
            do {
                try task.run()
                task.waitUntilExit()
                if task.terminationStatus == 0 {
                    // This check is not foolproof but adds defense-in-depth
                }
            } catch {
                // If we can't execute bash, device might be jailbroken
            }
        }
        
        // Check for debuggers
        if getppid() == 1 {
            // Parent process is init, possible debugging
            return true
        }
        
        return false
    }
    
    func isDeviceSecure() -> Bool {
        // Additional checks for secure environment
        let isJailbroken = isDeviceJailbroken()
        let isSimulator = ProcessInfo.processInfo.isiOSAppOnMac || ProcessInfo.processInfo.isEmulator
        
        return !isJailbroken && !isSimulator
    }
    
    func validateSecurity() -> Bool {
        guard isDeviceSecure() else {
            // Log security violation
            print("Security violation detected: Device not secure")
            return false
        }
        
        return true
    }
}

// MARK: - Trade Execution Manager
class TradeExecutionManager {
    private let apiClient: SecureAPIClient
    private let portfolioManager: PortfolioManager
    private let integrityChecker: DeviceIntegrityChecker
    
    init(apiClient: SecureAPIClient, portfolioManager: PortfolioManager) {
        self.apiClient = apiClient
        self.portfolioManager = portfolioManager
        self.integrityChecker = DeviceIntegrityChecker.shared
    }
    
    func executeTrade(symbol: String, quantity: Int, type: TradeType, completion: @escaping (Result<TradeResponse, Error>) -> Void) {
        // Security check before executing any trade
        guard integrityChecker.validateSecurity() else {
            completion(.failure(TradeError.deviceNotSecure))
            return
        }
        
        // Validate trade parameters
        guard quantity > 0 else {
            completion(.failure(TradeError.invalidQuantity))
            return
        }
        
        // Check if user has enough funds or stocks for sell
        if type == .sell {
            let currentStocks = portfolioManager.getStockQuantity(symbol: symbol)
            if currentStocks < quantity {
                completion(.failure(TradeError.insufficientStocks))
                return
            }
        }
        
        // Fetch current stock price
        apiClient.fetchStockData(symbol: symbol) { [weak self] result in
            guard let self = self else { return }
            
            switch result {
            case .success(let stockData):
                let tradeRequest = TradeRequest(
                    symbol: symbol,
                    quantity: quantity,
                    type: type,
                    price: stockData.price
                )
                
                self.apiClient.executeTrade(trade: tradeRequest) { tradeResult in
                    switch tradeResult {
                    case .success(let tradeResponse):
                        // Update portfolio
                        if tradeResponse.status == .completed {
                            if type == .buy {
                                self.portfolioManager.addStock(symbol: symbol, quantity: quantity)
                            } else {
                                self.portfolioManager.removeStock(symbol: symbol, quantity: quantity)
                            }
                        }
                        completion(.success(tradeResponse))
                    case .failure(let error):
                        completion(.failure(error))
                    }
                }
                
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
}

// MARK: - Trade Error
enum TradeError: Error {
    case deviceNotSecure
    case invalidQuantity
    case insufficientStocks
    case invalidTradeData
}

